MAP
  CONFIG "MS_DEBUGLEVEL" "0"
  CONFIG "CPL_DEBUG" "OFF"
  NAME "imagery"
  STATUS ON
  SIZE 256 256
  EXTENT -8412731 4709462 -8223562 5067461
  UNITS METERS
  IMAGETYPE png24
  IMAGECOLOR 255 255 255

  PROJECTION
    "init=epsg:3857"
  END

  OUTPUTFORMAT
    NAME "png24"
    DRIVER "AGG/PNG"
    MIMETYPE "image/png"
    IMAGEMODE RGBA
    TRANSPARENT ON
    EXTENSION "png"
  END

  OUTPUTFORMAT
    NAME "geojson"
    DRIVER "OGR/GEOJSON"
    MIMETYPE "application/json; subtype=geojson"
    FORMATOPTION "STORAGE=stream"
    FORMATOPTION "FORM=SIMPLE"
  END

  WEB
    METADATA
      "ows_title"                      "Cloud-Native Imagery Server"
      "ows_abstract"                   "Multi-collection COG service via MapServer"
      "ows_onlineresource"             "http://localhost/mapserv"
      "ows_srs"                        "EPSG:3857 EPSG:4326 EPSG:6527"
      "ows_enable_request"             "*"
      "oga_enable_request"             "*"
      "wms_allow_getmap_without_styles" "true"
    END
  END

  CONFIG "MS_ERRORFILE" "stderr"
  CONFIG "AWS_NO_SIGN_REQUEST" "YES"
  CONFIG "GDAL_CACHEMAX" "128"
  CONFIG "VSI_CACHE" "TRUE"
  CONFIG "VSI_CACHE_SIZE" "33554432"
  CONFIG "GDAL_DISABLE_READDIR_ON_OPEN" "TRUE"
  CONFIG "GDAL_HTTP_MULTIPLEX" "YES"
  CONFIG "GDAL_HTTP_VERSION" "2"
  CONFIG "GDAL_HTTP_MERGE_CONSECUTIVE_RANGES" "YES"
  CONFIG "CPL_VSIL_CURL_ALLOWED_EXTENSIONS" ".tif,.tiff"

  LAYER
    NAME "cog-extents-nj-2020-1ft"
    TYPE POLYGON
    STATUS ON
    TEMPLATE "unused"
    EXTENT 190000 30000 665000 925000
    CONNECTIONTYPE OGR
    CONNECTION "/usr/src/mapfiles/nj_2020_tileindex_6527.fgb"
    DATA "nj-2020-1ft_tileindex_6527"
    PROJECTION
      "init=epsg:6527"
    END
    METADATA
      "ows_title"          "New Jersey 2020 1-foot Imagery footprints"
      "ows_srs"            "EPSG:3857 EPSG:4326"
      "gml_featureid"      "file_name"
      "gml_geometries"     "msGeometry"
      "gml_include_items"  "all"
      "ows_enable_request"             "*"
      "wfs_enable_request"             "*"
      "oga_enable_request"             "*"
      "wfs_getfeature_formatlist"      "geojson,gml3,gml2"
      "ows_maxfeatures"                "50000"
    END
  END

  LAYER
    NAME "cog-tileindex-nj-2020-1ft"
    TYPE POLYGON
    STATUS OFF
    EXTENT 190000 30000 665000 925000
    CONNECTIONTYPE OGR
    CONNECTION "/usr/src/mapfiles/nj_2020_tileindex_6527.fgb"
    DATA "nj-2020-1ft_tileindex_6527"
    PROJECTION
      "init=epsg:6527"
    END
  END

  LAYER
    NAME "nj-2020"
    TYPE RASTER
    STATUS ON
    TILEINDEX "cog-tileindex-nj-2020-1ft"
    TILEITEM "location"
    PROCESSING "BANDS=1,2,3"
    PROCESSING "USE_MASK_BAND=NO"
    PROCESSING "SCALE=0,65535"
    PROCESSING "RESAMPLE=AVERAGE"
    PROJECTION
      "init=epsg:6527"
    END
    METADATA
      "ows_title"       "New Jersey 2020 1-foot Imagery"
      "ows_attribution" "NJ Office of GIS / NJGIN"
    END
  END

END
